// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cost;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;

import java.util.List;
import java.util.Set;

import org.eclipse.rdf4j.model.Literal;
import org.eclipse.rdf4j.model.Value;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.junit.jupiter.api.Test;

class BagEstimateMathTest {

	@Test
	void innerJoinUsesFiniteTupleFrequencies() {
		BagEstimate left = finite("left", List.of("code"),
				List.of(row("A"), row("A"), row("B")));
		BagEstimate right = finite("right", List.of("code"),
				List.of(row("A"), row("B"), row("B"), row("C")));

		BagEstimate joined = EstimateMath.innerJoin(left, right, Set.of("code"));

		assertEquals(4.0d, joined.rows(), 0.0d,
				"Join rows should be sum(freqLeft(code) * freqRight(code))");
		assertEquals(2.0d, joined.variable("code").distinctRows(), 0.0d,
				"Joined variable distinct rows should only count keys that occur on both sides");
	}

	@Test
	void innerJoinPreservesMultiColumnValuesCorrelationAndDuplicates() {
		BagEstimate left = finite("left", List.of("code", "enc"),
				List.of(row("A", "e1"), row("A", "e1"), row("A", "e2"), row("B", "e1")));
		BagEstimate right = finite("right", List.of("code", "enc", "cond"),
				List.of(row("A", "e1", "c1"), row("A", "e1", "c2"), row("A", "e2", "c3"),
						row("B", "e2", "c4")));

		BagEstimate joined = EstimateMath.innerJoin(left, right, Set.of("code", "enc"));

		assertEquals(5.0d, joined.rows(), 0.0d,
				"Multi-column VALUES must join by tuple frequency, not independent per-variable sets");
		assertEquals(3.0d, joined.variable("cond").distinctRows(), 0.0d,
				"Right-only finite tuple stats should keep the exact joined condition cardinality");
	}

	@Test
	void finiteRelationsDoNotHashStoreBackedValues() {
		Value codeLeft = new HashUnsafeValue("DX-200");
		Value codeRight = new HashUnsafeValue("DX-200");
		BagEstimate left = BagEstimate.exact(1.0d, "left")
				.withFiniteRelation(FiniteRelationEstimate.fromRows(List.of("code"), List.of(List.of(codeLeft)),
						"left"));
		BagEstimate right = BagEstimate.exact(1.0d, "right")
				.withFiniteRelation(FiniteRelationEstimate.fromRows(List.of("code"), List.of(List.of(codeRight)),
						"right"));

		BagEstimate joined = EstimateMath.innerJoin(left, right, Set.of("code"));

		assertEquals(1.0d, joined.rows(), 0.0d,
				"Finite VALUES relation math must not call Value.hashCode() on store-backed values");
	}

	@Test
	void leftJoinAddsOnlyUnmatchedLeftRowsAndMarksRightVariablesNullable() {
		BagEstimate left = finite("left", List.of("code"),
				List.of(row("A"), row("A"), row("B")));
		BagEstimate right = finite("right", List.of("code", "label"),
				List.of(row("B", "b1"), row("B", "b2"), row("C", "c1")));

		BagEstimate joined = EstimateMath.leftJoin(left, right, Set.of("code"));

		assertEquals(4.0d, joined.rows(), 0.0d,
				"One matching left row fans out to two RHS rows and two unmatched left rows survive");
		assertEquals(2.0d, joined.variable("label").boundRows(), 0.0d,
				"Right-only variable should be bound only on matched join rows");
		assertEquals(2.0d, joined.variable("label").nullableRows(), 0.0d,
				"Right-only variable should be nullable on unmatched left rows");
	}

	@Test
	void differenceKeepsAllRowsWhenThereAreNoSharedVariables() {
		BagEstimate left = finite("left", List.of("leftCode"),
				List.of(row("A"), row("B")));
		BagEstimate right = finite("right", List.of("rightCode"),
				List.of(row("A"), row("C")));

		BagEstimate difference = EstimateMath.difference(left, right, Set.of());

		assertEquals(2.0d, difference.rows(), 0.0d,
				"SPARQL MINUS without shared variables must keep the left input unchanged");
		assertEquals(2.0d, difference.variable("leftCode").boundRows(), 0.0d);
	}

	@Test
	void filterScalesRowsAndVariableCoverage() {
		BagEstimate input = finite("input", List.of("code"),
				List.of(row("A"), row("B"), row("C"), row("D")));

		BagEstimate filtered = EstimateMath.filter(input, 0.25d, "test-filter");

		assertEquals(1.0d, filtered.rows(), 0.0d);
		assertEquals(1.0d, filtered.variable("code").boundRows(), 0.0d);
	}

	@Test
	void groupUsesFiniteTupleDistinctCount() {
		BagEstimate input = finite("input", List.of("enc", "code"),
				List.of(row("e1", "A"), row("e1", "A"), row("e2", "A"), row("e2", "B")));

		BagEstimate grouped = EstimateMath.group(input, Set.of("enc"));

		assertEquals(2.0d, grouped.rows(), 0.0d,
				"Grouping by ?enc should estimate one output row per distinct ?enc tuple");
		assertEquals(2.0d, grouped.memoryRows(), 0.0d);
	}

	@Test
	void distinctUsesProjectedFiniteTupleDistinctCount() {
		BagEstimate input = finite("input", List.of("enc", "code"),
				List.of(row("e1", "A"), row("e1", "A"), row("e2", "A"), row("e2", "B")));

		BagEstimate distinct = EstimateMath.distinct(input, Set.of("enc", "code"));

		assertEquals(3.0d, distinct.rows(), 0.0d);
		assertEquals(3.0d, distinct.memoryRows(), 0.0d);
	}

	@Test
	void unionAddsBagRowsAndVariableCoverage() {
		BagEstimate left = finite("left", List.of("code"), List.of(row("A"), row("B")));
		BagEstimate right = finite("right", List.of("code"), List.of(row("C"), row("D"), row("E")));

		BagEstimate union = EstimateMath.union(left, right);

		assertEquals(5.0d, union.rows(), 0.0d);
		assertEquals(5.0d, union.variable("code").boundRows(), 0.0d);
	}

	@Test
	void projectionDropsFiniteRelationsThatReferenceRemovedVariables() {
		BagEstimate input = finite("input", List.of("enc", "code"),
				List.of(row("e1", "A"), row("e2", "B")));

		BagEstimate projected = EstimateMath.project(input, Set.of("enc"));

		assertEquals(2.0d, projected.rows(), 0.0d);
		assertFalse(projected.finiteRelation(Set.of("enc", "code")).isPresent(),
				"Projection must not leave stale finite tuple relations for removed variables");
		assertEquals(2.0d, projected.variable("enc").distinctRows(), 0.0d);
	}

	@Test
	void extensionAddsConstantVariableWithoutChangingRows() {
		BagEstimate input = finite("input", List.of("enc"), List.of(row("e1"), row("e2")));

		BagEstimate extended = EstimateMath.extendConstant(input, "constant");

		assertEquals(2.0d, extended.rows(), 0.0d);
		assertEquals(1.0d, extended.variable("constant").distinctRows(), 0.0d);
		assertEquals(2.0d, extended.variable("constant").boundRows(), 0.0d);
	}

	@Test
	void sliceAccountsForOffsetLimitAndConsumedRows() {
		BagEstimate input = finite("input", List.of("enc"),
				List.of(row("e1"), row("e2"), row("e3"), row("e4"), row("e5")));

		BagEstimate slice = EstimateMath.slice(input, 2L, 2L);

		assertEquals(2.0d, slice.rows(), 0.0d);
		assertEquals(input.workRows() + 4.0d, slice.workRows(), 0.0d);
	}

	@Test
	void orderAddsSortWorkAndMemoryRows() {
		BagEstimate input = finite("input", List.of("enc"),
				List.of(row("e1"), row("e2"), row("e3"), row("e4")));

		BagEstimate ordered = EstimateMath.order(input);

		assertEquals(4.0d, ordered.rows(), 0.0d);
		assertEquals(4.0d, ordered.memoryRows(), 0.0d);
		assertEquals(input.workRows() + 8.0d, ordered.workRows(), 0.0d);
	}

	private static BagEstimate finite(String source, List<String> variables, List<List<Value>> rows) {
		return BagEstimate.exact(rows.size(), source)
				.withFiniteRelation(FiniteRelationEstimate.fromRows(variables, rows, source));
	}

	private static List<Value> row(String... values) {
		return java.util.Arrays.stream(values)
				.map(BagEstimateMathTest::literal)
				.map(Value.class::cast)
				.toList();
	}

	private static Literal literal(String value) {
		return SimpleValueFactory.getInstance().createLiteral(value);
	}

	private record HashUnsafeValue(String value) implements Value {

		@Override
		public String stringValue() {
			return value;
		}

		@Override
		public int hashCode() {
			throw new AssertionError("Store-backed values must not be hashed by finite relation estimates");
		}
	}
}
